'use client';
import { useState, useEffect } from 'react';
import { ArrowUp } from 'lucide-react';

export function ScrollToTop() {
  const [show, setShow] = useState(false);
  useEffect(() => {
    const el = document.getElementById('main-scroll') ?? window;
    const onScroll = () => setShow((el instanceof Window ? window.scrollY : (el as HTMLElement).scrollTop) > 300);
    el.addEventListener('scroll', onScroll);
    return () => el.removeEventListener('scroll', onScroll);
  }, []);
  function scrollUp() {
    const el = document.getElementById('main-scroll');
    if (el) el.scrollTo({ top: 0, behavior: 'smooth' });
    else window.scrollTo({ top: 0, behavior: 'smooth' });
  }
  if (!show) return null;
  return (
    <button onClick={scrollUp} className="fixed bottom-20 right-4 md:bottom-6 z-50 p-2.5 bg-brand-500 rounded-full text-white shadow-lg hover:bg-brand-400 transition-colors">
      <ArrowUp className="w-4 h-4" />
    </button>
  );
}
