'use client';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Zap, TrendingUp, BookOpen, Bookmark, User } from 'lucide-react';

const items = [
  { href: '/feed',     Icon: Zap,         label: '피드'   },
  { href: '/trends',   Icon: TrendingUp,   label: '트렌드' },
  { href: '/journal',  Icon: BookOpen,     label: '저널'   },
  { href: '/wishlist', Icon: Bookmark,     label: '관심'   },
  { href: '/profile',  Icon: User,         label: '프로필' },
];

export function BottomNav() {
  const pathname = usePathname();
  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 md:hidden bg-surface-base/95 backdrop-blur border-t border-surface-border">
      <div className="flex">
        {items.map(({ href, Icon, label }) => {
          const active = pathname === href;
          return (
            <Link key={href} href={href} className={`flex-1 flex flex-col items-center gap-1 py-3 text-[10px] font-medium transition-colors ${active ? 'text-brand-500' : 'text-zinc-500 hover:text-zinc-300'}`}>
              <Icon className="w-5 h-5" />
              {label}
            </Link>
          );
        })}
      </div>
    </nav>
  );
}
